const downloadListAutoTrashCandidates = `-- name: DownloadListAutoTrashCandidates :many
SELECT InfoHash FROM Download
WHERE DeletedAt IS NULL
AND State IN ('imported', 'error')
AND LastActivityAt < ?
`

// DownloadListAutoTrashCandidates returns InfoHashes of live Downloads
// in terminal states whose last activity is older than the threshold.
// Active-state Downloads (queued/downloading/downloaded) are never
// auto-trashed: those are still in flight and belong to the user until
// they explicitly delete them.
func (q *Queries) DownloadListAutoTrashCandidates(lastactivityat int64) ([]string, error) {
	rows, err := q.db.QueryContext(q.ctx, downloadListAutoTrashCandidates, lastactivityat)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []string
	for rows.Next() {
		var infohash string
		if err := rows.Scan(&infohash); err != nil {
			return nil, err
		}
		items = append(items, infohash)
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

